// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title StridePool
 * @notice Fitness commitment protocol — stake MON, walk, earn from those who didn't.
 * @dev Reentrancy protected. Pull-payment pattern for safe withdrawals.
 */
contract StridePool {

    // ─── State ────────────────────────────────────────────────────────────────

    address public owner;
    address public oracle;
    uint256 public nextPoolId;

    struct Pool {
        uint256 stakeCost;      // MON required to join
        uint256 stepGoal;       // total steps needed to win
        uint256 createdAt;      // timestamp of creation
        bool finalized;         // payout done?
        address[] members;
    }

    mapping(uint256 => Pool) public pools;
    mapping(uint256 => mapping(address => uint256)) public stepsSubmitted;
    mapping(uint256 => mapping(address => uint256)) public stakedAmount;
    mapping(uint256 => mapping(address => bool)) public hasJoined;

    // Pull-payment: winners claim instead of auto-transfer (prevents reentrancy)
    mapping(address => uint256) public pendingWithdrawals;

    // Soulbound badge: 0 = none, 1 = Week Warrior, 2 = Iron Strider
    mapping(address => uint256) public badge;

    // Reentrancy guard
    bool private _locked;

    // ─── Events ───────────────────────────────────────────────────────────────

    event PoolCreated(uint256 indexed poolId, address indexed creator, uint256 stakeCost, uint256 stepGoal);
    event PlayerJoined(uint256 indexed poolId, address indexed player);
    event StepsLogged(uint256 indexed poolId, address indexed player, uint256 steps, uint256 date);
    event PoolFinalized(uint256 indexed poolId, uint256 winnerCount, uint256 loserPool);
    event BadgeAwarded(address indexed player, uint256 level);
    event Withdrawal(address indexed player, uint256 amount);

    // ─── Modifiers ────────────────────────────────────────────────────────────

    modifier noReentrancy() {
        require(!_locked, "Reentrant call");
        _locked = true;
        _;
        _locked = false;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    modifier onlyOracle() {
        require(msg.sender == oracle, "Not oracle");
        _;
    }

    modifier poolExists(uint256 poolId) {
        require(poolId < nextPoolId, "Pool does not exist");
        _;
    }

    modifier notFinalized(uint256 poolId) {
        require(!pools[poolId].finalized, "Pool already finalized");
        _;
    }

    // ─── Constructor ──────────────────────────────────────────────────────────

    constructor(address _oracle) {
        require(_oracle != address(0), "Invalid oracle address");
        owner = msg.sender;
        oracle = _oracle;
    }

    // ─── Core Functions ───────────────────────────────────────────────────────

    /**
     * @notice Create a new step challenge pool. Caller becomes first member.
     * @param stepGoal Total steps needed across challenge duration to win
     */
    function createPool(uint256 stepGoal)
        external
        payable
        returns (uint256 poolId)
    {
        require(msg.value > 0, "Must stake MON to create pool");
        require(stepGoal > 0, "Step goal must be greater than 0");

        poolId = nextPoolId++;
        Pool storage p = pools[poolId];
        p.stakeCost = msg.value;
        p.stepGoal = stepGoal;
        p.createdAt = block.timestamp;
        p.members.push(msg.sender);

        stakedAmount[poolId][msg.sender] = msg.value;
        hasJoined[poolId][msg.sender] = true;

        emit PoolCreated(poolId, msg.sender, msg.value, stepGoal);
        emit PlayerJoined(poolId, msg.sender);
    }

    /**
     * @notice Join an existing pool by staking the exact same amount as creator.
     * @param poolId ID of the pool to join
     */
    function joinPool(uint256 poolId)
        external
        payable
        poolExists(poolId)
        notFinalized(poolId)
    {
        Pool storage p = pools[poolId];
        require(msg.value == p.stakeCost, "Must stake exact pool amount");
        require(!hasJoined[poolId][msg.sender], "Already in this pool");
        require(p.members.length < 100, "Pool is full"); // gas safety cap

        p.members.push(msg.sender);
        stakedAmount[poolId][msg.sender] = msg.value;
        hasJoined[poolId][msg.sender] = true;

        emit PlayerJoined(poolId, msg.sender);
    }

    /**
     * @notice Submit step count — must be signed by the trusted oracle.
     * @param poolId Pool to submit to
     * @param steps Number of steps being submitted
     * @param date Day identifier (use Unix day: block.timestamp / 86400)
     * @param signature Oracle's ECDSA signature over (sender, poolId, steps, date)
     */
    function submitSteps(
        uint256 poolId,
        uint256 steps,
        uint256 date,
        bytes calldata signature
    )
        external
        poolExists(poolId)
        notFinalized(poolId)
    {
        require(hasJoined[poolId][msg.sender], "Not a member of this pool");
        require(steps > 0, "Steps must be greater than 0");

        // Verify oracle signature
        bytes32 messageHash = keccak256(
            abi.encodePacked(msg.sender, poolId, steps, date)
        );
        bytes32 ethSignedHash = keccak256(
            abi.encodePacked("\x19Ethereum Signed Message:\n32", messageHash)
        );
        require(
            _recoverSigner(ethSignedHash, signature) == oracle,
            "Invalid oracle signature"
        );

        stepsSubmitted[poolId][msg.sender] += steps;

        emit StepsLogged(poolId, msg.sender, steps, date);
    }

    /**
     * @notice Finalize the pool. Calculates winners, queues payouts, mints badges.
     * @dev Uses pull-payment pattern — winners must call withdraw() after.
     * @param poolId Pool to finalize
     */
    function finalize(uint256 poolId)
        external
        poolExists(poolId)
        notFinalized(poolId)
    {
        Pool storage p = pools[poolId];
        p.finalized = true;

        uint256 loserPool = 0;
        uint256 totalWinnerSteps = 0;
        uint256 winnerCount = 0;

        // Pass 1: calculate loser pool and total winner steps
        for (uint256 i = 0; i < p.members.length; i++) {
            address m = p.members[i];
            if (stepsSubmitted[poolId][m] >= p.stepGoal) {
                totalWinnerSteps += stepsSubmitted[poolId][m];
                winnerCount++;
            } else {
                loserPool += stakedAmount[poolId][m];
            }
        }

        // Pass 2: queue withdrawals for winners
        for (uint256 i = 0; i < p.members.length; i++) {
            address m = p.members[i];
            uint256 mySteps = stepsSubmitted[poolId][m];

            if (mySteps >= p.stepGoal) {
                uint256 bonus = 0;
                if (totalWinnerSteps > 0) {
                    // Proportional share of loser pool based on steps walked
                    bonus = (mySteps * loserPool) / totalWinnerSteps;
                }
                // Queue payout (pull-payment — no direct transfer here)
                pendingWithdrawals[m] += stakedAmount[poolId][m] + bonus;

                // Award badge
                if (badge[m] == 0) {
                    badge[m] = 1; // Week Warrior
                    emit BadgeAwarded(m, 1);
                }
            }
            // Losers get nothing — their stake funded the winners
        }

        emit PoolFinalized(poolId, winnerCount, loserPool);
    }

    /**
     * @notice Winners call this to claim their payout after finalize().
     * @dev Pull-payment pattern prevents reentrancy attacks.
     */
    function withdraw() external noReentrancy {
        uint256 amount = pendingWithdrawals[msg.sender];
        require(amount > 0, "Nothing to withdraw");

        // Zero out BEFORE transfer (prevents reentrancy)
        pendingWithdrawals[msg.sender] = 0;

        (bool success, ) = payable(msg.sender).call{value: amount}("");
        require(success, "Transfer failed");

        emit Withdrawal(msg.sender, amount);
    }

    // ─── View Functions ───────────────────────────────────────────────────────

    function getMembers(uint256 poolId)
        external
        view
        poolExists(poolId)
        returns (address[] memory)
    {
        return pools[poolId].members;
    }

    function getPoolDetails(uint256 poolId)
        external
        view
        poolExists(poolId)
        returns (
            uint256 stakeCost,
            uint256 stepGoal,
            uint256 memberCount,
            bool finalized,
            uint256 totalStaked
        )
    {
        Pool storage p = pools[poolId];
        uint256 _totalStaked = p.members.length * p.stakeCost;
        return (p.stakeCost, p.stepGoal, p.members.length, p.finalized, _totalStaked);
    }

    function getMemberSteps(uint256 poolId, address member)
        external
        view
        returns (uint256)
    {
        return stepsSubmitted[poolId][member];
    }

    // ─── Admin ────────────────────────────────────────────────────────────────

    /**
     * @notice Update oracle address if compromised
     */
    function updateOracle(address newOracle) external onlyOwner {
        require(newOracle != address(0), "Invalid address");
        oracle = newOracle;
    }

    // ─── Internal ─────────────────────────────────────────────────────────────

    function _recoverSigner(bytes32 hash, bytes calldata sig)
        internal
        pure
        returns (address)
    {
        require(sig.length == 65, "Invalid signature length");
        bytes32 r;
        bytes32 s;
        uint8 v;
        assembly {
            r := calldataload(sig.offset)
            s := calldataload(add(sig.offset, 32))
            v := byte(0, calldataload(add(sig.offset, 64)))
        }
        require(v == 27 || v == 28, "Invalid signature v value");
        return ecrecover(hash, v, r, s);
    }
}

